if (Pulsars.getFlagShowPulsars()) {
    core.debug("Pulsars are visible");
}

// Read using property
var visible = core.getStelProperty('Pulsars.pulsarsVisible');

// Write using property
core.setStelProperty('Pulsars.pulsarsVisible', true);

if (Pulsars.getFilteredMode()) {
    core.debug("Pulsar filter is enabled");
}

// Show only nearby pulsars (DM < 150)
Pulsars.setFilteredMode(true);
Pulsars.setFilterValue(150);

// Show all pulsars
Pulsars.setFilteredMode(false);

// Show only low DM pulsars (nearby)
Pulsars.setFilterValue(100);

// Show higher DM pulsars
Pulsars.setFilterValue(300);

if (Pulsars.getDisplayMode()) {
    core.debug("Pulsar distribution mode is enabled");
}

// Show pulsar distribution density
Pulsars.setDisplayMode(true);

// Show individual pulsar markers
Pulsars.setDisplayMode(false);

if (Pulsars.getGlitchFlag()) {
    core.debug("Glitching pulsars have separate color");
}

// Highlight glitching pulsars with different color
Pulsars.setGlitchFlag(true);

// Use same color for all pulsars
Pulsars.setGlitchFlag(false);

// Set normal pulsars to green
var green = core.vec3f(0.2, 0.8, 0.2);
Pulsars.setMarkerColor(green);

// Set to cyan
var cyan = core.vec3f(0.2, 0.7, 0.9);
Pulsars.setMarkerColor(cyan);

// Read color using property
var colorStr = core.getStelProperty('Pulsars.markerColor');
var parts = colorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);

// Write using method
var newColor = core.vec3f(0.2, 0.8, 0.2);
Pulsars.setMarkerColor(newColor);

// Set glitching pulsars to orange
var orange = core.vec3f(1.0, 0.5, 0.2);
Pulsars.setGlitchColor(orange);

// Reset to default darker blue
var darkBlue = core.vec3f(0.2, 0.3, 1.0);
Pulsars.setGlitchColor(darkBlue);

if (Pulsars.getUpdatesEnabled()) {
    core.debug("Automatic pulsar catalog updates are enabled");
}

// Enable automatic catalog updates
Pulsars.setUpdatesEnabled(true);

// Disable automatic updates
Pulsars.setUpdatesEnabled(false);

// Manually update pulsar catalog
Pulsars.updateJSON();
core.debug("Pulsar catalog update started...");

// Wait for update to complete
core.wait(30);
core.debug("Pulsar catalog updated");

// Update monthly
Pulsars.setUpdateFrequencyDays(30);

// Update yearly
Pulsars.setUpdateFrequencyDays(365);

var state = Pulsars.getUpdateState();
if (state === 0) core.debug("Updating catalog...");
else if (state === 1) core.debug("No updates needed");
else if (state === 2) core.debug("Catalog updated successfully");
else if (state === 3) core.debug("Download error occurred");

if (Pulsars.getEnableAtStartup()) {
    core.debug("Pulsars will load on next startup");
}

// Enable Pulsars on next startup
Pulsars.setEnableAtStartup(true);

// Disable Pulsars on next startup
Pulsars.setEnableAtStartup(false);

if (Pulsars.getFlagShowPulsarsButton()) {
    core.debug("Pulsars toolbar button is visible");
}

// Show Pulsars button on toolbar
Pulsars.setFlagShowPulsarsButton(true);

// Hide Pulsars button
Pulsars.setFlagShowPulsarsButton(false);

// Reset all Pulsars plugin settings to defaults
Pulsars.restoreDefaults();
core.debug("Pulsars settings restored to defaults");

// Get Crab Pulsar
var pulsar = Pulsars.getByID("PSR J0534+2200");
if (pulsar) {
    core.debug("Found: " + pulsar.getEnglishName());
    core.debug("Period: " + pulsar.getPeriod() + " seconds");
    core.debug("DM: " + pulsar.getDM() + " pc/cm³");
    core.moveToObject(pulsar.getEnglishName(), 3);
} else {
    core.debug("Pulsar not found in catalog");
}

var allPulsars = Pulsars.getAllPulsars();
core.debug("Total pulsars: " + allPulsars.length);

// Print first 10 pulsar names
for (var i = 0; i < Math.min(10, allPulsars.length); i++) {
    core.debug(allPulsars[i].getEnglishName());
}

var pulsar = Pulsars.searchByID("PSR J0534+2200");
if (pulsar) {
    core.debug("Moving to Crab Pulsar");
    core.moveToObject(pulsar.getEnglishName(), 3);
}

var pulsar = Pulsars.searchByName("Crab Pulsar");
if (pulsar) {
    core.debug("Found Crab Pulsar");
    core.debug("Rotation period: " + pulsar.getPeriod() + " s");
    core.moveToObject(pulsar.getEnglishName(), 3);
}
